struct FoveatedStreamingApp: App {
    let session = FoveatedStreamingSession()

    var body: some Scene {
        WindowGroup {
            Button("Connect") {
                Task {
                    try await session.connect(endpoint: .systemDiscovered)
                }
            }
        }

        ImmersiveSpace(foveatedStreaming: session)
    }
}
